#include <stdio.h>
#include <stdlib.h>
#include <time.h>

static void swap(int *a,int *b){int t=*a;*a=*b;*b=t;}

static int partition(int arr[],int low,int high){int pivotIdx=low+rand()%(high-low+1);swap(&arr[pivotIdx],&arr[high]);int pivot=arr[high];int i=low;for(int j=low;j<high;++j){if(arr[j]<pivot){swap(&arr[i],&arr[j]);++i;}}swap(&arr[i],&arr[high]);return i;}

static void quickSort(int arr[],int low,int high){if(low<high){int p=partition(arr,low,high);quickSort(arr,low,p-1);quickSort(arr,p+1,high);}}

int main(){srand((unsigned)time(NULL));int T;if(scanf("%d",&T)!=1)return 0;while(T--){int N;scanf("%d",&N);int *a=malloc(N*sizeof(int));for(int i=0;i<N;++i)scanf("%d",&a[i]);quickSort(a,0,N-1);for(int i=0;i<N;++i){printf("%d",a[i]);if(i+1==N)printf("\n");else printf(" ");}free(a);}return 0;}

